SELECT /* base.ec.st :: StSettle :: selectList */ s.* , vnd.vendor_nm AS vendor_nm , ste.site_nm AS site_nm , cd_ss.code_label AS settle_status_cd_nm FROM st_settle s LEFT JOIN sy_vendor vnd ON vnd.vendor_id = s.vendor_id LEFT JOIN sy_site ste ON ste.site_id = s.site_id LEFT JOIN sy_code cd_ss ON cd_ss.code_grp = 'SETTLE_STATUS' AND cd_ss.code_value = s.settle_status_cd
ORDER BY s.settle_id ASC ORDER BY s.settle_id DESC ORDER BY s.settle_ym ASC ORDER BY s.settle_ym DESC ORDER BY s.reg_date DESC
LIMIT #{limit} OFFSET #{offset}

SELECT /* base.ec.st :: StSettle :: selectPageList */ s.* , vnd.vendor_nm AS vendor_nm , ste.site_nm AS site_nm , cd_ss.code_label AS settle_status_cd_nm FROM st_settle s LEFT JOIN sy_vendor vnd ON vnd.vendor_id = s.vendor_id LEFT JOIN sy_site ste ON ste.site_id = s.site_id LEFT JOIN sy_code cd_ss ON cd_ss.code_grp = 'SETTLE_STATUS' AND cd_ss.code_value = s.settle_status_cd
ORDER BY s.settle_id ASC ORDER BY s.settle_id DESC ORDER BY s.settle_ym ASC ORDER BY s.settle_ym DESC ORDER BY s.reg_date DESC
LIMIT #{limit} OFFSET #{offset}

