UPDATE st_settle /* base.ec.st :: StSettle :: updateSelective */
site_id = #{siteId}, vendor_id = #{vendorId}, settle_ym = #{settleYm}, settle_start_date = #{settleStartDate}, settle_end_date = #{settleEndDate}, total_order_amt = #{totalOrderAmt}, total_return_amt = #{totalReturnAmt}, total_claim_cnt = #{totalClaimCnt}, total_discnt_amt = #{totalDiscntAmt}, commission_rate = #{commissionRate}, commission_amt = #{commissionAmt}, settle_amt = #{settleAmt}, adj_amt = #{adjAmt}, etc_adj_amt = #{etcAdjAmt}, final_settle_amt = #{finalSettleAmt}, settle_status_cd = #{settleStatusCd}, settle_status_cd_before = #{settleStatusCdBefore}, settle_memo = #{settleMemo}, upd_by = #{updBy}, upd_date = #{updDate},
WHERE settle_id = #{settleId}
